function s(b,h,M,g){let i=3*b,f=3*(M-b)-i,I=1-i-f,c=3*h,O=3*(g-h)-c,x=1-c-O;function m(t){return((I*t+f)*t+i)*t}function z(t){return((x*t+O)*t+c)*t}function F(t){return(3*I*t+2*f)*t+i}function N(t,o){let e,r,n,u,l,p;for(n=t,p=0;p<8;p++){if(u=m(n)-t,Math.abs(u)<o)return n;if(l=F(n),Math.abs(l)<1e-6)break;n-=u/l}if(e=0,r=1,n=t,n<e)return e;if(n>r)return r;for(;e<r;){if(u=m(n),Math.abs(u-t)<o)return n;t>u?e=n:r=n,n=.5*(r-e)+e}return n}return function(t,o=1e-6){return z(N(t,o))}}var a={ease:s(.25,.1,.25,1),linear:s(0,0,1,1),easeIn:s(.42,0,1,1),easeOut:s(0,0,.58,1),easeInOut:s(.42,0,.58,1)};a["ease-in"]=a.easeIn,a["ease-out"]=a.easeOut,a["ease-in-out"]=a.easeInOut;export{s as a,a as b};
